 CREATE TABLE active_mesocycle (start_date date, id uuid, status text, focus text, name text, created_at timestamp with time zone, notes text, end_date date);
 CREATE TABLE exercise_progression (exercise_id uuid, reps_at_max_weight integer, exercise text, mesocycle_name text, max_weight_kg numeric, week_number integer, date date);
 CREATE TABLE exercises (muscle_group text, name text NOT NULL, id uuid NOT NULL DEFAULT gen_random_uuid(), created_at timestamp with time zone DEFAULT now(), movement_pattern text, equipment text, notes text);
 CREATE TABLE goals (target_date date, created_at timestamp with time zone DEFAULT now(), id uuid NOT NULL DEFAULT gen_random_uuid(), exercise_id uuid, mesocycle_id uuid, target_value numeric NOT NULL, target_reps integer, achieved_at timestamp with time zone, notes text, goal_type text NOT NULL);
 CREATE TABLE mesocycle_days (created_at timestamp with time zone DEFAULT now(), day_number integer NOT NULL, name text NOT NULL, notes text, id uuid NOT NULL DEFAULT gen_random_uuid(), mesocycle_id uuid);
 CREATE TABLE mesocycle_planned_exercises (target_reps text, target_sets integer, target_rpe numeric, created_at timestamp with time zone DEFAULT now(), notes text, id uuid NOT NULL DEFAULT gen_random_uuid(), mesocycle_day_id uuid, exercise_id uuid, exercise_order integer NOT NULL);
 CREATE TABLE mesocycles (status text DEFAULT 'active'::text, notes text, start_date date NOT NULL, priority_muscles ARRAY, end_date date, rpe_end integer DEFAULT 10, progression_style text DEFAULT 'auto'::text, rpe_start integer DEFAULT 7, id uuid NOT NULL DEFAULT gen_random_uuid(), created_at timestamp with time zone DEFAULT now(), name text NOT NULL, focus text);
 CREATE TABLE superset_groups (created_at timestamp with time zone DEFAULT now(), workout_id uuid, id uuid NOT NULL DEFAULT gen_random_uuid(), name text);
 CREATE TABLE weekly_targets (target_weight_kg numeric, mesocycle_id uuid, week_number integer NOT NULL, mesocycle_day_id uuid, exercise_id uuid, exercise_order integer NOT NULL, id uuid NOT NULL DEFAULT gen_random_uuid(), target_sets integer NOT NULL, created_at timestamp with time zone DEFAULT now(), superset_group text, target_reps text NOT NULL, notes text);
 CREATE TABLE weekly_volume_by_muscle (week_number integer, mesocycle_name text, total_sets bigint, muscle_group text, total_volume_kg numeric, mesocycle_id uuid);
 CREATE TABLE workout_exercise_notes (workout_id uuid, joint_discomfort integer, id uuid NOT NULL DEFAULT gen_random_uuid(), notes text NOT NULL, exercise_id uuid, created_at timestamp with time zone DEFAULT now(), pump_quality integer);
 CREATE TABLE workout_log (weight_kg numeric, superset_group_id uuid, rpe numeric, reps integer, set_order integer, exercise_id uuid, workout_rating integer, week_number integer, date date, workout_id uuid, mesocycle_id uuid, mesocycle_name text, mesocycle_focus text, day_name text, workout_notes text, exercise text, muscle_group text, equipment text, movement_pattern text, set_type text, set_notes text, exercise_notes text);
 CREATE TABLE workout_sets (id uuid NOT NULL DEFAULT gen_random_uuid(), created_at timestamp with time zone DEFAULT now(), rpe numeric, reps integer, weight_kg numeric, set_order integer NOT NULL, superset_group_id uuid, exercise_id uuid, workout_id uuid, set_type text, notes text);
 CREATE TABLE workout_volume_by_muscle (date date, total_sets bigint, total_volume_kg numeric, muscle_group text, workout_id uuid);
 CREATE TABLE workouts (pre_session_notes text, rating integer, created_at timestamp with time zone DEFAULT now(), week_number integer, ended_at timestamp with time zone, started_at timestamp with time zone, date date NOT NULL DEFAULT CURRENT_DATE, sleep_quality integer, energy_level integer, muscle_soreness jsonb, mesocycle_day_id uuid, mesocycle_id uuid, notes text, id uuid NOT NULL DEFAULT gen_random_uuid());
